class Agent:
    def __init__(self, name, specialty):
        self.name = name
        self.specialty = specialty

    def accept_task(self, task):
        print(f"{self.name} (Specialty: {self.specialty}) accepted task: {task}")

swarm = [
    Agent("DataBot", "data_cleaning"),
    Agent("Polyglot", "translation"),
    Agent("Coder", "programming")
]

task = "Translate this text to French"
task_type = "translation"

print("Broadcasting task to swarm...")
for agent in swarm:
    if agent.specialty == task_type:
        agent.accept_task(task)
        break
